概念（前置知识）阶由欧拉定理可知，对 $a\in \mathbb{Z}$，$m\in\mathbb{N}^{*}$，若 $\gcd(a,m)=1$，则 $a^{\varphi(m)}\equiv 1\pmod m$。 因此满足同余式 $a^n \equiv 1 \pmod m$ 的最小正整数 $n$ 存在，这个 $n$ 称作 $a$ 模 $m$ 的阶，记作 $\delta_m(a)$。 性质 $a,a^2,\cdots,a^{\delta_m(a)}$ 模 $m$ 两两不同余。 证明：假设存在两个数 $i
e j$，且 $a^i\equiv a^j\pmod m$，则有 $a^{|i-j|}\equiv 1\pmod p$。 但是显然的有：$0&lt;|i-j|&lt;\delta_m(a)$，这与阶的最小性矛盾，故原命题成立。 若 $a^n \equiv 1 \pmod m$，则 $\delta_m(a)\mid n$。 证明：$\delta_m(a)$ 是使 $a^n \equiv 1 \pmod m$ 成立的最小正整数，显然其他任意指数 $n$ 一定是它的倍数。 推论：若 $a^p\equiv a^q\pmod m$，则有 $p\equiv q\pmod{\delta_m(a)}$。 设 $m\in\mathbb{N}^{*}$，$a,b\in\mathbb{Z}$，$\gcd(a,m)=\gcd(b,m)=1$，则 $\delta_m(ab)=\delta_m(a)\delta_m(b)$ 成立的充分必要条件是 $\gcd ig(\delta_m(a),\delta_m(b) ig)=1$ 证明：一般情况下 $\delta_m(ab)=\operatorname{lcm}(\delta_m(a),\delta_m(b))$，于是显然。 设 $k \in \mathbb{N}$，$m\in \mathbb{N}^{*}$，$a\in\mathbb{Z}$，$\gcd(a,m)=1$，则 $\delta_m(a^k)=\dfrac{\delta_m(a)}{\gcd ig(\delta_m(a),k ig)}$ 证明：注意到：$$ egin{aligned}a^{k\delta_m(a^k)} &amp;=(a^k)^{\delta_m(a^k)}\equiv 1 \pmod m \&amp;\Rightarrow \delta_m(a)\mid k\delta_m(a^k)\&amp;\Rightarrow \dfrac{\delta_m(a)}{\gcd ig(\delta_m(a),k ig)}\mid\delta_m(a^k)\end{aligned}$$又由 $a^{\delta_m(a)}\equiv 1 \pmod m$，可知：$(a^k)^{ rac{\delta_m(a)}{\gcd(\delta_m(a),k)}}=(a^{\delta_m(a)})^{ rac{k}{\gcd(\delta_m(a),k)}}\equiv 1 \pmod m$ 故 $\delta_m(a^k)\mid\dfrac{\delta_m(a)}{\gcd(\delta_m(a),k)}$ 综上，得 $\delta_m(a^k)=\dfrac{\delta_m(a)}{\gcd ig(\delta_m(a),k ig)}$ 原根设 $m \in \mathbb{N}^{*}$，$a\in \mathbb{Z}$。若 $\gcd(a,m)=1$，且 $\delta_m(a)=\varphi(m)$，则称 $a$ 为模 $m$ 的原根。 原根判定定理设 $m \geqslant 3, \gcd(t,n)=1$，则 $t$ 是模 $n$ 的原根的充要条件是，对于 $\varphi(n)$ 的每个素因数 $p$，都有 $a^{ rac{\varphi(n)}{p}}
ot\equiv 1\pmod n$。 证明：显然。 12345678bool check(int t,int n){ if(gcd(t,n)!=1) return false; getFac(phi[n]);//分解质因数 for(int i=1;i&lt;=facTot;i++){ if(qwqmi(t,phi[n]/facList[i],n)==1) return false; }//优化，不用判断所有素因数 return true;} $\operatorname{check}$ 中if(gcd(t,n)!=1) return false; 还可写做 if(qwqmi(t,phi[n],n)!=1)return false; 因为根据欧拉定理 $\gcd(t,n)=1$ 与 $t^{\varphi(n)}\equiv 1 \pmod{n}$ 是等价的。 原根个数若一个数 $m$ 有原根，则它原根的个数为 $\varphi(\varphi(m))$。 证明： 若 $m$ 有原根 $g$，则：$\delta_m(g^k)=\dfrac{\delta_m(g)}{\gcd ig(\delta_m(g),k ig)}=\dfrac{\varphi(m)}{\gcd ig(\varphi(m),k ig)}$ 所以若 $\gcd ig(k,\varphi(m) ig)=1$，则有：$\delta_m(g^k)=\varphi(m)$，即 $g^k$ 也是模 $m$ 的原根。 而满足 $\gcd ig(\varphi(m),k ig)=1$ 且 $1\leq k \leq \varphi(m)$ 的 $k$ 有 $\varphi(\varphi(m))$ 个。所以原根就有 $\varphi(\varphi(m))$ 个。 但证明到这里还不够，因为这只是说明了原根 $g$ 的某些次幂也是原根，还需要证明非 $g$ 次幂的一定不是原根。 假设存在 $mg^k\equiv1 \pmod{n}$，其中 $k&lt;\varphi(n),gcd(m,n)=1$。由此可见 $m$ 是 $g^k$ 的逆元。 于是显然，在模意义下 $m$ 仍是 $g$ 的次幂，所以只有 $g$ 的次幂才能是原根。 原根存在定理一个数 $m$ 存在原根当且仅当 $m=2,4,p^{\alpha},2p^{\alpha}$，其中 $p$ 为奇素数，$\alpha\in \mathbb{N}^{*}$。 证明：太麻烦不证了 代码123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899100101102103104105106107108109110111112113114115116117118119120121122123124125126127128129#include&lt;iostream&gt;#include&lt;cstdio&gt;#include&lt;cstring&gt;#include&lt;vector&gt;#include&lt;algorithm&gt;using namespace std;typedef long long LL;const int N=1e6+10;int phi[N];int T;int n,d;int facList[10],facTot;int prime[N],pTot;bool vis[N];int minRoot;vector&lt;int&gt; ans;int tott;int cnt,cnt2;void init(){ phi[1]=1; for(int i=2;i&lt;N;i++){ if(!vis[i]){ prime[++pTot]=i; phi[i]=i-1; } for(int j=1;prime[j]&lt;=(N-1)/i;j++){ vis[prime[j]*i]=true; if(i%prime[j]==0){ phi[i*prime[j]]=phi[i]*prime[j]; break; }else{ phi[i*prime[j]]=phi[i]*(prime[j]-1); } } }}bool hasRoot(int x){ if(x==2||x==4) return true; if(!(x&amp;1)) x&gt;&gt;=1; if(!(x&amp;1)) return false; for(int i=3;i*i&lt;=x;i++){ if(x%i==0){ while(x%i==0) x/=i; return x==1; } } return true;}int qwqmi(int a,int b,int mod){ int res=1; while(b){ if(b&amp;1) res=(LL)res*a%mod; a=(LL)a*a%mod; b&gt;&gt;=1; } return res;}int gcd(int a,int b){ return b?gcd(b,a%b):a;}void getFac(int t){ facTot=0; for(int i=1;i&lt;=pTot&amp;&amp;prime[i]&lt;=t;i++){ if(t%prime[i]==0){ facList[++facTot]=prime[i]; while(t%prime[i]==0) t/=prime[i]; } } if(t&gt;1) facList[++facTot]=t;}bool check(int t,int n){ if(gcd(t,n)!=1) return false; getFac(phi[n]); for(int i=1;i&lt;=facTot;i++){ if(qwqmi(t,phi[n]/facList[i],n)==1) return false; } return true;}void getAns(int minRoot,int n){ ans.clear(); int g=1; for(int i=1;i&lt;=phi[n];i++){ g=(long long)g*minRoot%n; if(gcd(i,phi[n])==1) ans.push_back(g); } sort(ans.begin(),ans.end());}int main(){ init(); scanf(&quot;%d&quot;,&amp;T); while(T--){ tott=0; cnt=0; cnt2=0; scanf(&quot;%d%d&quot;,&amp;n,&amp;d); if(!hasRoot(n)){ puts(&quot;0&quot;); puts(&quot;&quot;); continue; } minRoot=0; for(int i=1;i&lt;=n;i++){ if(check(i,n)){ minRoot=i; break; } } getAns(minRoot,n); int m=ans.size(); printf(&quot;%d
&quot;,m); for(int i=d-1;i&lt;m;i+=d){ printf(&quot;%d &quot;,ans[i]); } puts(&quot;&quot;); } return 0;}
